function parseOllama(input) {
  // Try $json.response first (format:json mode)
  const sources = [input.response, input.data, JSON.stringify(input)];
  for (const src of sources) {
    if (!src) continue;
    const text = typeof src === 'string' ? src : JSON.stringify(src);
    // Try direct parse
    try {
      const d = JSON.parse(text);
      if (d && typeof d === 'object' && !d.model && !d.done) return d;
    } catch(e) {}
    // Try stream reconstruction
    try {
      const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
      let rec = '';
      for (const l of lines) {
        try { const o = JSON.parse(l); if (typeof o.response === 'string') rec += o.response; } catch(e) {}
      }
      if (rec) {
        rec = rec.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/\s*```$/i,'').trim();
        const s = rec.indexOf('{'); const e = rec.lastIndexOf('}');
        if (s !== -1 && e !== -1) return JSON.parse(rec.slice(s, e+1));
      }
    } catch(e) {}
  }
  throw new Error('Could not parse Ollama response');
}

