    production: production,
    testing: testing,
    security: security,
    deployment: deployment
  },
  message: 'Full report available in full_lifecycle_report field'
} }];

const input = $json;
const report = input.full_lifecycle_report || 'No report generated';

// Convert to base64 for n8n binary
const base64 = Buffer.from(report, 'utf8').toString('base64');

return [{
  json: {
    ...input,
    export_status: 'ready',
    filename: 'lifecycle-report-' + new Date().toISOString().slice(0,10) + '.txt',
    message: 'Report ready for download in Binary tab'
  },
  binary: {
    lifecycle_report_txt: {
      data: base64,
      mimeType: 'text/plain',
      fileName: 'AI-Workflow-Nutrition-Lifecycle-Report.txt',
      fileExtension: 'txt'
    }
  }
}];

const raw = $json.response || $json.data || JSON.stringify($json);

// Get TXT report binary from previous node
let txtBinary = null;
try {
  const txtItems = $items('Export Lifecycle Report TXT');
  if (txtItems && txtItems[0] && txtItems[0].binary) {
    txtBinary = txtItems[0].binary.lifecycle_report_txt;
  }
} catch(e) {}

// Extract code from Ollama response
let code = typeof raw === 'string' ? raw : JSON.stringify(raw);
try {
  const lines = code.split('\n').map(l => l.trim()).filter(Boolean);
  let rec = '';
  for (const l of lines) {
    try { const o = JSON.parse(l); if (o.response) rec += o.response; } catch(e) {}
  }
  if (rec) code = rec;
} catch(e) {}

code = code.replace(/^```python\s*/i,'').replace(/^```\s*/i,'').replace(/\s*```$/i,'').trim();

const base64Code = Buffer.from(code, 'utf8').toString('base64');

const binary = {
  app_py: {
    data: base64Code,
    mimeType: 'text/x-python',
    fileName: 'app.py',
    fileExtension: 'py'
  }
};

if (txtBinary) {
  binary.lifecycle_report_txt = txtBinary;
}

return [{
  json: {
    pipeline_status: 'COMPLETED',
    workflow: 'central-workflow-semi-auto-v9',
    mode: 'semi-autonomous',
    human_checkpoints_passed: 3,
    steps_completed: [
      '1 — Design Thinking',
      '2 — Architecture',
      '3 — Production',
      '4 — Test & Improvement',
      '5 — Security',
      '6 — Deployment & Maintenance',
      '7 — Final Package',
      '8 — Code Generation'
    ],
    generated_files: ['lifecycle-report.txt', 'app.py'],
    app_py_preview: code.slice(0, 300),
    message: 'Download app.py and lifecycle-report.txt from the Binary tab.'
  },
  binary
}];
